// Load a sub-level
FLatentActionInfo LatentInfo;
LatentInfo.CallbackTarget = this;
LatentInfo.ExecutionFunction = TEXT("OnLevelLoaded");
LatentInfo.UUID = 1;
LatentInfo.Linkage = 0;

UGameplayStatics::LoadStreamLevel(GetWorld(), TEXT("Dungeon_01"), true, true, LatentInfo);

// Callback when loaded
UFUNCTION()
void OnLevelLoaded() {
    UE_LOG(LogTemp, Log, TEXT("Dungeon loaded!"));
}

// Unload
UGameplayStatics::UnloadStreamLevel(GetWorld(), TEXT("Dungeon_01"), LatentInfo, false);

// Check if loaded
ULevelStreaming* Level = UGameplayStatics::GetStreamingLevel(GetWorld(), TEXT("Dungeon_01"));
if (Level && Level->IsLevelLoaded()) {
    // Level is in memory
}
